That comparison will never be true. More likely you want to compare the value from the database with roomname. My code does that, although I am not certain if snapshot.key is correct for your data structure. But this code is still wasteful. You don't need to listen for all rooms to know if a specific one exists. You just need to check for that one. This can be done with a simple read of just the one location:
var duplicate = function(roomname, callback) {
 var found = false;
 roomsRef.child(roomname).once("value", function(snapshot) {
 if (snapshot.exists()) {
 found = true;
 callback(snapshot.val())
 }
 });
}

