::END UPDATE 8.2.2016::
//::HACK:: Only works when there is 1 purchase transaction. $all_account_transactions = Recurly_TransactionList::getForAccount($refund_transaction->details[0]->account_code);
foreach ($all_account_transactions as $account_transaction) 
{
 if($account_transaction->action=="purchase" && 
 $account_transaction->subscription->get()->uuid == $refund_transaction->subscription->get()->uuid )
 {
 //This is a purchase transaction and its from the same subscription as the $refund_transaction. //If there's only 1 purchase transaction then this is your transaction that was refunded. //If there's multiple purchase transactions you'll have to figure out which one you want to apply the refund to
 }
}

