 case DDLogFlagWarning : aslLogLevel = ASL_LEVEL_ERR; break;
 case DDLogFlagInfo : aslLogLevel = ASL_LEVEL_WARNING; break; // Regular NSLog's level
 case DDLogFlagDebug :
 case DDLogFlagVerbose :
 default : aslLogLevel = ASL_LEVEL_NOTICE; break;
 }

